+mod tests {
+    use super::*;
+
+    #[test]
+    fn error_from_io() {
+        let io_err = std::io::Error::new(std::io::ErrorKind::NotFound, "file missing");
+        let err: Error = Error::from(io_err);
+        match &err {
+            Error::Io(e) => assert_eq!(e.kind(), std::io::ErrorKind::NotFound),
